1. **Realtime subscriptions**:
   - In a custom hook `useRealtimeStock()`:
     ```ts
     import { supabase } from '../lib/supabaseClient';

     export const useRealtimeStock = (productId: string) => {
       useEffect(() => {
         const channel = supabase
           .channel('stock-changes')
           .on('postgres_changes', 
             { event: 'UPDATE', schema: 'public', table: 'stock_levels', filter: `product_id=eq.${productId}` },
             (payload) => {
               // Update local cache/state with new stock level
               queryClient.setQueryData(['product', productId], (old) => ({...old, stock: payload.new.quantity}));
             }
           )
           .subscribe();
         return () => supabase.removeChannel(channel);
       }, [productId]);
     };
     ```
   - Subscribe to `stock_levels` changes for all visible product IDs on POS page.
